module zero_crossing_detector (
    input clk,
    input rst,
    input signal_in,
    output reg zero_cross
);

reg signal_last;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        signal_last <= 1'b0;
        zero_cross <= 1'b0;
    end else begin
        zero_cross <= (signal_last == 1'b0 && signal_in == 1'b1) || 
                      (signal_last == 1'b1 && signal_in == 1'b0);
        signal_last <= signal_in;
    end
end

endmodule
